              $data['metrica_product_id'] = $data['product_id'];
              $data['metrica_product_name'] = $product_info['name'];
              if ((float)$product_info['special']) {
                $data['metrica_product_price'] = $this->currency->format($this->tax->calculate($product_info['special'], $product_info['tax_class_id'], $this->config->get('config_tax')), $this->session->data['currency'], '', false);
              } else {
                $data['metrica_product_price'] = $this->currency->format($this->tax->calculate($product_info['price'], $product_info['tax_class_id'], $this->config->get('config_tax')), $this->session->data['currency'], '', false);
              }
              $data['metrica_product_manufacturer'] = $product_info['manufacturer'];
              $data['metrica_product_category'] = "";

              $product_categories = $this->model_catalog_product->getCategories($product_info["product_id"]);

              if (count($product_categories) > 0) {
                $category = array_pop($product_categories);
                $category_info = $this->model_catalog_category->getCategory($category['category_id']);
                if ($category_info) {
                  $data['metrica_product_category'] = $category_info['name'];
                } else {
                  $data['metrica_product_category'] = "";
                }
              } else {
                $data['metrica_product_category'] = "";
              }
            } else {
              $this->load->model('setting/setting');
              $log_status = $this->model_setting_setting->getSettingValue('analytics_yandex_metrica_log');
              if ($log_status) {
                $log_ym = new Log('log_yandex_metrica.log');
                $log_ym->write('Required parameters not found (name and ID)', true);
              }
            }

          
            public function getProductDataForYandexMetrica() {
              $this->load->model('catalog/category');
              $this->load->model('catalog/product');

              if (isset($this->request->post['event'])) {
                $event = $this->request->post['event'];
              } else {
                $event = 'add';
              }

              if (isset($this->request->post['id_type']) && $this->request->post['id_type'] == 'key') {
                $this->load->model('extension/module/yandex_metrica');
                $product_data_from_cart = $this->model_extension_module_yandex_metrica->getProductFromCart($this->request->post['id']);
                $product_id = $product_data_from_cart['product_id'];
              } elseif (isset($this->request->post['id'])) {
                $product_id = (int)$this->request->post['id'];
              } else {
                $product_id = 0;
              }

              if (isset($this->request->post['quantity']) && $this->request->post['quantity'] === 'null' && $this->request->post['id_type'] === 'key') {
                $quantity = $product_data_from_cart['quantity'];
              } elseif (isset($this->request->post['quantity']) && $this->request->post['quantity'] === 'null' && $this->request->post['id_type'] === 'product_id' && $event === 'add') {
                $quantity = 1;
              } else {
                $quantity = (int)$this->request->post['quantity'];
              }

              if ($product_id === 0) {
                $this->load->model('setting/setting');
                $log_status = $this->model_setting_setting->getSettingValue('analytics_yandex_metrica_log');
                if ($log_status) {
                  $log_ym = new Log('log_yandex_metrica.log');
                  $log_ym->write('Required parameters not found (ID)', true);
                }
              }

              $product_info = $this->model_catalog_product->getProduct($product_id);
              $product_categories = $this->model_catalog_product->getCategories($product_id);

              if(count($product_categories) > 0) {
                $category = array_pop($product_categories);
                $category_info = $this->model_catalog_category->getCategory($category['category_id']);
                if ($category_info) {
                  $product_category = $category_info['name'];
                } else {
                  $product_category = "";
                }
              } else {
                $product_category = "";
              }

              $json = [];

              if ($event == 'add') {
                $json = [
                  'currency_code' => $this->session->data['currency'],
                  'product' => [
                    'id' => $product_info['product_id'],
                    'name' => $product_info['name'],
                    'price' => $this->currency->format($this->tax->calculate($product_info['price'], $product_info['tax_class_id'], $this->config->get('config_tax')), $this->session->data['currency'], '', false),
                    'brand' => $product_info['manufacturer'],
                    'category' => $product_category,
                    'quantity' => $quantity,
                  ],
                ];
              } elseif ($event == 'remove') {
                $json = [
                  'currency_code' => $this->session->data['currency'],
                  'product' => [
                    'id' => $product_info['product_id'],
                    'name' => $product_info['name'],
                    'category' => $product_category,
                    'quantity' => $quantity,
                  ],
                ];
              }

              $this->response->addHeader('Content-Type: application/json');
              $this->response->setOutput(json_encode($json));
            }


  product_id = +$("input[name*='product_id']").val();
