  }
  if (!empty($data['yandex_metrica_status']) && $data['yandex_metrica_status'] === '1') {
    if (!empty($data['yandex_metrics'])) {
      foreach ($data['yandex_metrics'] as $key => $value) {
        if (!empty($value['ya_metrica_webvizor']) && $value['ya_metrica_webvizor'] == true) {
          $data['yandex_metrics'][$key]['ya_metrica_webvizor'] = 'true';
        } else {
          $data['yandex_metrics'][$key]['ya_metrica_webvizor'] = 'false';
        }
      }
    }
  }

        
          {% if (yandex_metrica_status is not empty) and (yandex_metrica_status == 1) %} 
          <!-- Yandex.Metrica counters -->
          {% if yandex_metrics is not empty %}
          <script type="text/javascript">
            window.dataLayer = window.dataLayer || [];
          </script>
          <script type="text/javascript">
            (function(m,e,t,r,i,k,a){m[i]=m[i]||function(){(m[i].a=m[i].a||[]).push(arguments)};
            m[i].l=1*new Date();k=e.createElement(t),a=e.getElementsByTagName(t)[0],k.async=1,k.src=r,a.parentNode.insertBefore(k,a)})
            (window, document, "script", "https://mc.yandex.ru/metrika/tag.js", "ym");

            {% for metrica in yandex_metrics %}
            ym({{ metrica.code }}, "init", {
              clickmap:true,
              trackLinks:true,
              accurateTrackBounce:true,
              webvisor:{{ metrica.ya_metrica_webvizor }},
              ecommerce:"dataLayer",
              params: { __ym: {"ymCmsPlugin": { "cms": "opencart", "cmsVersion":"{{ cms_version }}", "pluginVersion":"1.1.9"}}}
            });
            {% endfor %}
          </script>
          <noscript>
            <div>
              {% for metrica in yandex_metrics %}
              <img src="https://mc.yandex.ru/watch/{{ metrica.code }}" style="position:absolute; left:-9999px;" alt="" />
              {% endfor %}
            </div>
          </noscript>
          {% endif %}
          <!-- /Yandex.Metrica counters -->
          {% endif %}

          
            $data['metrica_order_id'] = $this->session->data['order_id'];
            $data['currency_code'] = $this->session->data['currency'];
            $this->load->model('account/order');
            $this->load->model('catalog/category');
            $this->load->model('catalog/product');
            $this->load->model('setting/setting');
            $this->load->model('extension/module/yandex_metrica');

            $order_info = $this->model_extension_module_yandex_metrica->getOrder($data['metrica_order_id']);
            $order_products = $this->model_account_order->getOrderProducts($data['metrica_order_id']);

            if (isset($order_info['total'])) {
              $data['metrica_total'] = $this->currency->format($order_info['total'], $this->session->data['currency'], '', false);
            } else {
              $data['metrica_total'] = 0;
            }
            # $data['metrica_total'] = $this->currency->format($order_info['total'], $this->session->data['currency'], '', false);
            if (isset($order_info['currency_code'])) {
              $data['currency_code'] = $order_info['currency_code'];
            } else {
              $data['currency_code'] = $this->session->data['currency'];
            }
            # $data['currency_code'] =  $order_info['currency_code'];

            if (isset($this->session->data['coupon'])) {
              $data['metrica_coupon'] = $this->session->data['coupon'];
            }

            if (empty($this->session->data['order_id']) && $order_products) {
              $log_status = $this->model_setting_setting->getSettingValue('analytics_yandex_metrica_log');
              $log_ym = new Log('log_yandex_metrica.log');
              if ($log_status) {
                $log_ym->write('Required parameters not found (Purchase)', true);
              }
            }

            foreach($order_products as $order_product) {
              $product_info = $this->model_catalog_product->getProduct($order_product["product_id"]);
              $categories_product = $this->model_catalog_product->getCategories($order_product["product_id"]);
              if($product_info) {
                $metrica_product_category = "";
                if(count($categories_product) > 0) {
                  $category = array_pop($categories_product);
                  $category_info = $this->model_catalog_category->getCategory($category['category_id']);
                  if ($category_info)
                    $metrica_product_category = $category_info['name'];
                }

                $price = $this->currency->format($this->tax->calculate($order_product["price"], $product_info['tax_class_id'], $this->config->get('config_tax')), $this->session->data['currency'], '', false);

                $data['metrica_order_products'][] = array(
                  "metrica_product_id" => $order_product["product_id"],
                  "metrica_product_name" => $order_product["name"],
                  "metrica_product_price" => $price,
                  "metrica_product_quantity" => $order_product["quantity"],
                  "metrica_product_manufacturer" => $product_info['manufacturer'],
                  "metrica_product_category" => $metrica_product_category,
                );
              }
            }


  {% if (metrica_order_id is defined and metrica_order_id) %} 
    <script type="text/javascript">
        dataLayer.push({
          "ecommerce": {
            "currencyCode": "{{ currency_code }}",
            "purchase": {
              "actionField": {
                "id" : "{{ metrica_order_id }}",
                {% if metrica_coupon is defined and metrica_coupon %}
                "coupon": "{{ metrica_coupon }}",
                {% endif %}
                "revenue": "{{ metrica_total }}"
              },
              "products": [
                {% for product in metrica_order_products %} 
                {
                  "id": "{{ product["metrica_product_id"] }}",
                  "name": "{{ product["metrica_product_name"] }}",
                  "price": {{ product["metrica_product_price"] }},
                  "brand": "{{ product["metrica_product_manufacturer"] }}",
                  "category": "{{ product["metrica_product_category"] }}",
                  "quantity": {{ product["metrica_product_quantity"] }}
                },
                {% endfor %} 
              ]
            }
          }
        });
    </script>
  {% endif %}
